let callTrace = []

async_hooks.createHook({
  init: (asyncId, type, triggerAsyncId, resource) => {
    callTrace.push({ resource, asyncId, triggerAsyncId })
  },
  before(asyncId) {

  },
  after(asyncId) {

  },
  destroy(asyncId) {
    // console.log(`destroy asyncId:${asyncId}`);
  }
}).enable()

async function test() {

  const aa = await Promise.resolve(1);
  const bb = await test2()
}

async function test2() {
  console.log(callTrace)
  return 1
}

test()

